            )
            # Add detailed cache breakdown if available
            if (
                hasattr(recv_obj, "cached_tokens_details")
                and recv_obj.cached_tokens_details
            ):
                meta_info["cached_tokens_details"] = recv_obj.cached_tokens_details[
